import{b as e,J as l,g as a,j as d}from"./chunks/framework.BFn5dPDD.js";const h=JSON.parse('{"title":"분양 조건 설정","description":"","frontmatter":{},"headers":[],"relativePath":"project/settings.md","filePath":"project/settings.md","lastUpdated":1779899975000}'),n={name:"project/settings.md"};function r(i,t,s,g,x,y){return l(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="분양-조건-설정" tabindex="-1">분양 조건 설정 <a class="header-anchor" href="#분양-조건-설정" aria-label="Permalink to &quot;분양 조건 설정&quot;">​</a></h1><p>프로젝트의 납부 일정, 계약금 및 공급 가격, 구비 서류, 유상 옵션 등 분양 계약에 직접적으로 적용되는 상세 조건을 설정합니다.</p><h2 id="납부-회차-등록" tabindex="-1">납부 회차 등록 <a class="header-anchor" href="#납부-회차-등록" aria-label="Permalink to &quot;납부 회차 등록&quot;">​</a></h2><p>계약금, 중도금, 잔금 등 분양 대금의 납부 회차를 정의하고, 각 회차별 납부 기한 및 선납할인/연체가산 기준을 설정합니다.</p><ul><li><strong>위치</strong>: <code>프로젝트 설정 &gt; 분양 조건 설정 &gt; 납부 회차 등록</code></li></ul><h4 id="주요-입력-항목" tabindex="-1">주요 입력 항목 <a class="header-anchor" href="#주요-입력-항목" aria-label="Permalink to &quot;주요 입력 항목&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">라벨</th><th style="text-align:center;">필수입력 여부</th><th style="text-align:left;">비고</th></tr></thead><tbody><tr><td style="text-align:left;">타입 종류</td><td style="text-align:center;">필수</td><td style="text-align:left;">공동주택, 오피스텔 등 시설 용도별 회차 구분</td></tr><tr><td style="text-align:left;">회차 종류</td><td style="text-align:center;">필수</td><td style="text-align:left;">계약금, 중도금, 잔금, 업무대행비 등 항목 선택</td></tr><tr><td style="text-align:left;">계약금 산정방법</td><td style="text-align:center;"></td><td style="text-align:left;">(계약금인 경우) 등록 계약 금액 우선 또는 분양가 대비 비율 중 선택</td></tr><tr><td style="text-align:left;">납입회차 코드</td><td style="text-align:center;">필수</td><td style="text-align:left;">동일 회차 식별 코드 (중복 등록을 통한 분할 납부 가능)</td></tr><tr><td style="text-align:left;">납부순서</td><td style="text-align:center;">필수</td><td style="text-align:left;">동일 회차 내에서의 수납 순서</td></tr><tr><td style="text-align:left;">회차 명 / 별칭</td><td style="text-align:center;">필수</td><td style="text-align:left;">고지서 등에 표시될 회차 명칭</td></tr><tr><td style="text-align:left;">납부 약정금액</td><td style="text-align:center;"></td><td style="text-align:left;">정액으로 정해진 경우 입력 (예: 업무대행비)</td></tr><tr><td style="text-align:left;">납부비율(%)</td><td style="text-align:center;"></td><td style="text-align:left;">분양가 대비 납부 비율 (잔금은 자동 계산)</td></tr><tr><td style="text-align:left;">납부 약정일</td><td style="text-align:center;"></td><td style="text-align:left;">고정된 납부 기한이 있는 경우 입력</td></tr><tr><td style="text-align:left;">전회 기준 경과일수</td><td style="text-align:center;"></td><td style="text-align:left;">전 회차(예: 계약일)로부터 일정 기간 후 납부 시 설정</td></tr><tr><td style="text-align:left;">선납/연체 설정</td><td style="text-align:center;"></td><td style="text-align:left;">선납할인율, 연체가산율 및 각각의 적용 기준일 설정</td></tr></tbody></table><h2 id="계약-금액-등록" tabindex="-1">계약 금액 등록 <a class="header-anchor" href="#계약-금액-등록" aria-label="Permalink to &quot;계약 금액 등록&quot;">​</a></h2><p>차수 및 타입별로 고정된 계약 금액을 설정합니다.</p><ul><li><p><strong>등록 대상</strong>: 동호 미지정 계약이나 타입별(층별 구분 없이) 일괄 정액제 계약금을 운영할 때 등록합니다.</p></li><li><p><strong>적용 우선순위</strong>: 이 데이터가 등록된 경우, [납부 회차 등록]에서 설정한 계약금 납입 비율보다 <strong>우선하여 적용</strong>됩니다.</p></li><li><p><strong>참고</strong>: 각 유닛별 공급 가격의 일정 비율을 계약금으로 정하는 일반적인 경우에는 [납부 회차 등록]의 납입 비율이 자동 적용되므로 별도로 이 데이터를 등록할 필요가 없습니다.</p></li><li><p><strong>위치</strong>: <code>프로젝트 설정 &gt; 분양 조건 설정 &gt; 계약 금액 등록</code></p></li></ul><h4 id="주요-입력-항목-1" tabindex="-1">주요 입력 항목 <a class="header-anchor" href="#주요-입력-항목-1" aria-label="Permalink to &quot;주요 입력 항목&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">라벨</th><th style="text-align:center;">필수입력 여부</th><th style="text-align:left;">비고</th></tr></thead><tbody><tr><td style="text-align:left;">차수</td><td style="text-align:center;">필수</td><td style="text-align:left;">대상 계약 차수 그룹 선택</td></tr><tr><td style="text-align:left;">타입</td><td style="text-align:center;">필수</td><td style="text-align:left;">대상 유닛 타입 선택</td></tr><tr><td style="text-align:left;">회차별 납부금액</td><td style="text-align:center;">필수</td><td style="text-align:left;">해당 차수/타입에 적용할 정액 계약금액</td></tr></tbody></table><h2 id="공급-가격-등록" tabindex="-1">공급 가격 등록 <a class="header-anchor" href="#공급-가격-등록" aria-label="Permalink to &quot;공급 가격 등록&quot;">​</a></h2><p>동/타입/층별 범위에 따른 실제 공급 가격을 등록합니다. 건물가, 대지가, 부가세를 구분하여 관리합니다.</p><ul><li><strong>위치</strong>: <code>프로젝트 설정 &gt; 분양 조건 설정 &gt; 공급 가격 등록</code></li></ul><h4 id="주요-입력-항목-2" tabindex="-1">주요 입력 항목 <a class="header-anchor" href="#주요-입력-항목-2" aria-label="Permalink to &quot;주요 입력 항목&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">라벨</th><th style="text-align:center;">필수입력 여부</th><th style="text-align:left;">비고</th></tr></thead><tbody><tr><td style="text-align:left;">구분 / 차수 / 타입</td><td style="text-align:center;">필수</td><td style="text-align:left;">가격을 등록할 상세 범위 선택</td></tr><tr><td style="text-align:left;">층별 조건</td><td style="text-align:center;">필수</td><td style="text-align:left;">등록된 층 범위(저층, 기준층 등) 선택</td></tr><tr><td style="text-align:left;">건물가 / 대지가</td><td style="text-align:center;">필수</td><td style="text-align:left;">각 항목별 금액 입력 (단위: 원)</td></tr><tr><td style="text-align:left;">부가세</td><td style="text-align:center;">필수</td><td style="text-align:left;">건물분에 대한 부가세 입력</td></tr><tr><td style="text-align:left;">기준공급가</td><td style="text-align:center;">필수</td><td style="text-align:left;">건물가 + 대지가 + 부가세 합계 (자동 계산)</td></tr><tr><td style="text-align:left;">특별약정 추가</td><td style="text-align:center;"></td><td style="text-align:left;">특정 회차에 대해 비율이 아닌 확정 금액을 적용할 경우 설정</td></tr></tbody></table><h4 id="전체-계약건-공급가-재설정-관리자-전용" tabindex="-1">전체 계약건 공급가 재설정 (관리자 전용) <a class="header-anchor" href="#전체-계약건-공급가-재설정-관리자-전용" aria-label="Permalink to &quot;전체 계약건 공급가 재설정 (관리자 전용)&quot;">​</a></h4><p>공급 가격이나 계약 금액 정보를 수정한 후, 이미 등록된 모든 계약 데이터에 변경된 내용을 일괄 반영할 때 사용합니다.</p><ul><li><strong>미리보기</strong>: 실제 반영 전 업데이트 대상 계약 건수와 샘플 데이터를 콘솔 등을 통해 확인합니다.</li><li><strong>전체 공급가 재설정</strong>: 현재 등록된 최신 공급 가격 및 계약 금액 데이터를 기반으로 모든 계약 건의 가격 정보를 강제로 재설정합니다.</li><li><strong>주의사항</strong>: 이 작업은 복구가 불가능하며 등록된 모든 계약 데이터의 수납 약정 금액이 변경될 수 있으므로 매우 신중하게 실행해야 합니다.</li></ul><h2 id="구비-서류-등록" tabindex="-1">구비 서류 등록 <a class="header-anchor" href="#구비-서류-등록" aria-label="Permalink to &quot;구비 서류 등록&quot;">​</a></h2><p>계약 시 계약자가 제출해야 하는 증빙 서류 및 동의서 목록을 관리합니다.</p><ul><li><strong>위치</strong>: <code>프로젝트 설정 &gt; 분양 조건 설정 &gt; 구비 서류 등록</code></li></ul><h4 id="주요-입력-항목-3" tabindex="-1">주요 입력 항목 <a class="header-anchor" href="#주요-입력-항목-3" aria-label="Permalink to &quot;주요 입력 항목&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">라벨</th><th style="text-align:center;">필수입력 여부</th><th style="text-align:left;">비고</th></tr></thead><tbody><tr><td style="text-align:left;">서류구분</td><td style="text-align:center;">필수</td><td style="text-align:left;">증빙서류 또는 동의서류(약정서 등) 중 선택</td></tr><tr><td style="text-align:left;">서류 유형</td><td style="text-align:center;">필수</td><td style="text-align:left;">주민등록등본, 인감증명서 등 세부 유형 선택</td></tr><tr><td style="text-align:left;">필요 수량</td><td style="text-align:center;"></td><td style="text-align:left;">제출 받아야 할 서류 부수</td></tr><tr><td style="text-align:left;">필수 여부</td><td style="text-align:center;">필수</td><td style="text-align:left;">필수, 선택, 조건부 필수 중 선택</td></tr><tr><td style="text-align:left;">설명 / 표시 순서</td><td style="text-align:center;"></td><td style="text-align:left;">서류 지참 안내 시 참고사항 및 목록 노출 순서</td></tr></tbody></table><h2 id="옵션-품목-등록" tabindex="-1">옵션 품목 등록 <a class="header-anchor" href="#옵션-품목-등록" aria-label="Permalink to &quot;옵션 품목 등록&quot;">​</a></h2><p>발코니 확장, 시스템 에어컨, 가전제품 등 수분양자가 선택할 수 있는 유상 옵션 품목을 관리합니다.</p><ul><li><strong>위치</strong>: <code>프로젝트 설정 &gt; 분양 조건 설정 &gt; 옵션 품목 등록</code></li></ul><h4 id="주요-입력-항목-4" tabindex="-1">주요 입력 항목 <a class="header-anchor" href="#주요-입력-항목-4" aria-label="Permalink to &quot;주요 입력 항목&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">라벨</th><th style="text-align:center;">필수입력 여부</th><th style="text-align:left;">비고</th></tr></thead><tbody><tr><td style="text-align:left;">타입구분</td><td style="text-align:center;">필수</td><td style="text-align:left;">해당 옵션을 선택할 수 있는 대상 타입 (다중 선택 가능)</td></tr><tr><td style="text-align:left;">품목 코드 / 이름</td><td style="text-align:center;">필수</td><td style="text-align:left;">옵션 품목 식별 정보</td></tr><tr><td style="text-align:left;">세대 옵션</td><td style="text-align:center;"></td><td style="text-align:left;">규격, 색상 등 세부 선택 사항</td></tr><tr><td style="text-align:left;">제조사</td><td style="text-align:center;"></td><td style="text-align:left;">품목의 제조사 또는 브랜드</td></tr><tr><td style="text-align:left;">옵션 가격</td><td style="text-align:center;">필수</td><td style="text-align:left;">총 판매 가격</td></tr><tr><td style="text-align:left;">계약금 / 잔금</td><td style="text-align:center;"></td><td style="text-align:left;">옵션 대금의 분납 시 각 금액 설정</td></tr></tbody></table>',30)])])}const f=e(n,[["render",r]]);export{h as __pageData,f as default};
